FROM resistivity_readings
WHERE resistivity > 10.0;

external_knowledge:
- 'completed journeys' refers to surveys with a `status` of 'completed';
- 'paths taken' refers to the `line_id` of the survey lines;
- 'length of paths' refers to the `length` of the survey lines;
